widgets_values:
{
  "high_level_description": "A cute promotional e-commerce poster for a Double 11 pre-sale campaign, featuring fluffy pink Chinese typography, a smiling fuzzy handbag character, a blue fuzzy megaphone, gift boxes, and discount mini bags. The poster has a playful toy-like 3D commercial style with soft fur textures, bright pink and orange accents, and clear shopping discount information.",
  "style_description": {
    "aesthetics": "cute commercial poster, plush toy aesthetic, soft fluffy texture, Double 11 shopping campaign, cheerful, playful, kawaii, bright and promotional",
    "lighting": "soft studio lighting, bright commercial illumination, gentle shadows, glossy highlights on eyes and accessories, even lighting for clean poster readability",
    "medium": "graphic_design",
    "art_style": "3D plush illustration poster, fuzzy texture rendering, cute mascot product campaign, toy-like commercial visual, soft rounded shapes, high-saturation e-commerce design",
    "color_palette": ["#F9D9E6", "#F58DB7", "#F7A7C7", "#FF7B1A", "#6CCBFF", "#FCEAF1", "#FFFFFF", "#2A2A2A", "#FFD945"]
  },
  "compositional_deconstruction": {
    "background": "A soft pastel pink vertical poster background with subtle circular candy-like shapes and soft floating decorative dots. The entire composition feels fluffy, warm, and festive, with a gentle toy-store atmosphere suitable for an online shopping event poster.",
    "elements": [
      {
        "type": "text",
        "bbox": [25, 50, 170, 760],
        "text": "11.11提前购",
        "desc": "Large fluffy pink Chinese headline across the top, using thick rounded lettering with a fuzzy plush texture. The text should feel soft, tactile, and celebratory, like cotton candy or faux fur.",
        "color_palette": ["#F58DB7", "#F7A7C7", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [150, 40, 300, 790],
        "text": "放肆嗨购",
        "desc": "Even larger fluffy pink Chinese headline directly below the first line, dominating the top area. The typography is bold, plush, soft-edged, and visually exciting, forming the main Double 11 slogan.",
        "color_palette": ["#F58DB7", "#F7A7C7", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [35, 720, 110, 970],
        "desc": "A small rounded pink badge in the upper-right corner containing two stacked white pill labels, acting as a limited-edition or surprise benefits tag.",
        "color_palette": ["#F58DB7", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [45, 745, 70, 955],
        "text": "福袋限量发放",
        "desc": "Small white Chinese text inside the top pill-shaped label, clean and compact.",
        "color_palette": ["#FFFFFF", "#F58DB7"]
      },
      {
        "type": "text",
        "bbox": [72, 765, 100, 945],
        "text": "福利惊喜",
        "desc": "Small pink Chinese text inside the lower white pill label, centered and cheerful.",
        "color_palette": ["#F58DB7", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [180, 40, 265, 430],
        "desc": "A bright yellow rounded speech-label shape with a black smiley face icon on the left, used as a promo tag.",
        "color_palette": ["#FFD945", "#2A2A2A"]
      },
      {
        "type": "text",
        "bbox": [195, 115, 245, 400],
        "text": "福利大放送",
        "desc": "Bold black Chinese text centered inside the yellow promo label, highly readable and energetic.",
        "color_palette": ["#2A2A2A", "#FFD945"]
      },
      {
        "type": "text",
        "bbox": [180, 470, 285, 910],
        "text": "满额惠享",
        "desc": "Large bold dark pink Chinese text on the right side of the yellow label, using clean heavy sans-serif typography to announce full-spend promotions.",
        "color_palette": ["#E6397E", "#F58DB7"]
      },
      {
        "type": "obj",
        "bbox": [300, 70, 700, 930],
        "desc": "A large rounded orange rectangular panel in the middle of the poster serving as the main product showcase area. The panel contrasts strongly with the pink background and frames the plush mascot objects.",
        "color_palette": ["#FF7B1A", "#FFA24A"]
      },
      {
        "type": "text",
        "bbox": [330, 90, 390, 520],
        "text": "DOUBLE 11",
        "desc": "Large pale orange or light cream uppercase English text across the top area of the orange panel, clean, bold, and softly integrated into the panel.",
        "color_palette": ["#FFD8B8", "#FFF0E0"]
      },
      {
        "type": "obj",
        "bbox": [410, 170, 770, 620],
        "desc": "A large cute pink fuzzy handbag character centered slightly left within the orange panel. The bag has plush fur texture, two white fluffy handles with blue eyelets, oversized cartoon eyes, pink cheeks, and a smiling open mouth. The character feels like a toy mascot and is the primary visual focus.",
        "color_palette": ["#F7A7C7", "#FCEAF1", "#FFFFFF", "#2A2A2A", "#6CCBFF"]
      },
      {
        "type": "obj",
        "bbox": [350, 620, 720, 980],
        "desc": "A large blue fuzzy megaphone on the right side of the orange panel, angled toward the center. It has plush texture and a pink spherical detail inside the horn opening, reinforcing the promotional announcement theme.",
        "color_palette": ["#6CCBFF", "#9ADFFF", "#F58DB7"]
      },
      {
        "type": "obj",
        "bbox": [620, 20, 780, 220],
        "desc": "A pastel gift box in the lower-left area of the orange panel, decorated with fluffy pink trim and a large blue ribbon bow, sitting on the plush ground surface.",
        "color_palette": ["#DDF0FF", "#6CCBFF", "#F7A7C7", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [580, 560, 770, 700],
        "desc": "A small pink fuzzy mini handbag with a white percent sign printed on it, placed near the lower middle-right. It acts as a discount icon prop.",
        "color_palette": ["#F58DB7", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [560, 710, 770, 870],
        "desc": "A small blue fuzzy mini handbag with a white percent sign, placed beside the pink mini bag. It mirrors the sale theme and balances the scene.",
        "color_palette": ["#6CCBFF", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [700, 0, 1000, 1000],
        "desc": "A soft fluffy pink ground surface occupies the lower portion of the poster, like a plush carpet, supporting the promo objects and giving the entire poster a tactile cozy feeling.",
        "color_palette": ["#F7A7C7", "#FCEAF1", "#FFFFFF"]
      },
      {
        "type": "obj",
        "bbox": [740, 30, 860, 970],
        "desc": "A large rounded pink information banner with plush texture placed above the bottom price panel. It contains the main flash-sale slogan in big white text, with small decorative white dots at both ends.",
        "color_palette": ["#F58DB7", "#F7A7C7", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [770, 110, 840, 900],
        "text": "限时秒杀 疯狂嗨购",
        "desc": "Large bold white Chinese text centered inside the plush pink information banner, clearly announcing the limited-time sale.",
        "color_palette": ["#FFFFFF", "#F58DB7"]
      },
      {
        "type": "obj",
        "bbox": [850, 30, 955, 970],
        "desc": "A white rounded rectangular price and discount information panel spanning the lower part of the poster. It is divided into three vertical columns with subtle separators and contains the core promotional offers.",
        "color_palette": ["#FFFFFF", "#F7F7F7", "#F58DB7", "#2A2A2A"]
      },
      {
        "type": "text",
        "bbox": [875, 60, 950, 320],
        "text": "消费满200元\n减50",
        "desc": "Left discount block in the white panel, with smaller pink explanatory text above and very large black and pink numeric emphasis below.",
        "color_palette": ["#E6397E", "#2A2A2A", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [875, 360, 950, 650],
        "text": "充200得\n充200得240\n（充值卡金额）",
        "desc": "Center recharge offer block in the white panel, using mixed black and pink text with the key number 240 emphasized.",
        "color_palette": ["#E6397E", "#2A2A2A", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [875, 700, 950, 940],
        "text": "消费满100元\n减20",
        "desc": "Right discount block in the white panel, with a clear numeric emphasis and clean promotional layout.",
        "color_palette": ["#E6397E", "#2A2A2A", "#FFFFFF"]
      },
      {
        "type": "text",
        "bbox": [955, 300, 995, 700],
        "text": "LINN DESIGN",
        "desc": "Small black uppercase designer credit centered at the very bottom of the poster, subtle but legible.",
        "color_palette": ["#2A2A2A"]
      },
      {
        "type": "obj",
        "bbox": [0, 0, 1000, 1000],
        "desc": "The overall poster should have a polished e-commerce advertising finish with soft plush materials, rounded cute forms, highly readable promotional typography, and a joyful festival sale atmosphere. The visual language should feel toy-like, furry, and highly appealing for a Double 11 shopping campaign.",
        "color_palette": ["#F9D9E6", "#F58DB7", "#FF7B1A", "#6CCBFF", "#FFFFFF"]
      }
    ]
  }
}
